const inputItems = $input.all();
const MIN_CONTENT_LENGTH = 100;
const out = [];

for (const item of inputItems) {
  const data = item.json?.body ?? item.json;
  if (!data || !Array.isArray(data.countries)) continue;

  for (const c of data.countries) {
    for (const trend of (c.trends || [])) {
      const keyword = (trend.keyword || "").trim();
      if (!keyword) continue;

      const articles = Array.isArray(trend.articles) ? trend.articles : [];
      const good = articles.filter(a =>
        a &&
        a.success === true &&
        typeof a.content === "string" &&
        a.content.trim().length >= MIN_CONTENT_LENGTH
      );

      if (!good.length) continue;

      out.push({
        json: {
          keyword,
          country: c.country || "",
          geo: c.geo || "",
          summary_for_ai: good
            .map(a => (a.title ? `${a.title}\n` : "") + a.content.slice(0, 700))
            .join("\n\n---\n\n"),
        },
      });
    }
  }
}

return out.length ? out.slice(0, 10) : [{ json: { error: "No trends with sufficient content" } }];

